    if recall_count > 0:
        issues.append(f"{recall_count} content recall patterns")
    if ref_missing > 0:
        issues.append(f"{ref_missing} quizzes missing text refs")
    if year_cloze > 0:
        issues.append(f"{year_cloze} cloze with year blanks")
    if year_fill_in > 0:
